      active={active}
      plotW={plotW}
      plotH={plotH}
      strokeWidth={strokeWidth}
      hasAxes={hasAxes}
      valueDomain={valueDomain}
      timeRange={timeRange}
      showTicks={showTicks}
      yTicks={yTicks}
